    // Sobreescribimos syntax_error para dar mensajes más inteligentes
        public void syntax_error(Symbol s) {
                List<Integer> ids = expected_token_ids();
                LinkedList<String> listaNombres = new LinkedList<>();
                boolean faltaPuntoYComa = false;
                boolean esperaLlaveCierre = false;

                for (Integer id : ids) {
                    if (id >= 0 && id < sym.terminalNames.length) {
                        String nombre = sym.terminalNames[id];

                        // Banderas
                        if (nombre.equals("PUNTO_COMA")) faltaPuntoYComa = true;
                        if (nombre.equals("LLAVE_DER")) esperaLlaveCierre = true;

                        // TRADUCTOR DE TOKENS A SÍMBOLOS LEGIBLES
                        switch(nombre) {
                            // Básicos
                            case "NUMERO": listaNombres.add("un número"); break;
                            case "ID": listaNombres.add("un identificador"); break;

                            // Delimitadores
                            case "PUNTO_COMA": listaNombres.add("';'"); break;
                            case "LPAREN": listaNombres.add("'('"); break;
                            case "RPAREN": listaNombres.add("')'"); break;
                            case "LLAVE_IZQ": listaNombres.add("'{'"); break;
                            case "LLAVE_DER": listaNombres.add("'}'"); break;
                            case "CORCH_IZQ": listaNombres.add("'['"); break;
                            case "CORCH_DER": listaNombres.add("']'"); break;
                            case "COMA": listaNombres.add("','"); break;
                            case "DOS_PUNTOS": listaNombres.add("':'"); break;

                            // Operadores y Asignación
                            case "ASSIGN": listaNombres.add("'='"); break;
                            case "SUMA": listaNombres.add("'+'"); break;
                            case "RESTA": listaNombres.add("'-'"); break;
                            case "MULT": listaNombres.add("'*'"); break;
                            case "DIV": listaNombres.add("'/'"); break;

                            // Palabras Reservadas
                            case "T_INT": listaNombres.add("'int'"); break;
                            case "T_CHAR": listaNombres.add("'char'"); break;
                            case "T_BOOL": listaNombres.add("'bool'"); break;
                            case "IF": listaNombres.add("'if'"); break;
                            case "WHILE": listaNombres.add("'while'"); break;
                            case "FOR": listaNombres.add("'for'"); break;
                            case "RETURN": listaNombres.add("'return'"); break;

                            // Si no está en la lista, mostramos el nombre técnico
                            default: listaNombres.add(nombre);
                        }
                    }
                }

                String lexema = "";
                if (s.value != null) {
                    if (sym.terminalNames[s.sym].equals("LIT_CHAR") && s.value instanceof Integer) {
                        lexema = "'" + (char)((int)s.value) + "'";
                    } else {
                        lexema = s.value.toString();
                    }
                } else {
                    lexema = sym.terminalNames[s.sym];
                }

                String msg = "Token inesperado: " + lexema;

                // MENSAJES
                if (s.sym == sym.EOF) {
                    msg = "Final de archivo inesperado.";
                    if (esperaLlaveCierre) {
                        msg += " Falta la llave de cierre '}' del main.";
                    }
                }
                else if (faltaPuntoYComa) {
                     msg = "Error de Sintaxis: Probablemente falta un punto y coma (;) antes de " + lexema;
                }
                else if (!listaNombres.isEmpty()) {
                     msg += ". Se esperaba: " + listaNombres.toString();
                }

                report_error(msg, s);
        }

    public void report_error(String message, Object info) {
        int linea = -1; int columna = -1;
        if (info instanceof Symbol) {
            Symbol s = (Symbol) info;
            linea = s.left; columna = s.right;
        }
        GestorErrores.errorSintactico((linea+1), (columna+1), message);
    }

    public void report_fatal_error(String message, Object info) {
        if (!message.contains("Couldn't repair")) {
            report_error("Error fatal: " + message, info);
        }
    }


